Conversation.code:
// Multi-turn chat. Pass an array of Content objects as the first argument;
// the adaptor forwards it as `contents` to generateContent.
prompt(
  [
    { role: 'user',  parts: [{ text: 'Hi there!' }] },
    { role: 'model', parts: [{ text: 'Hello — how can I help?' }] },
    { role: 'user',  parts: [{ text: $.data.userMessage }] },
  ],
  {
    model: 'gemini-2.5-flash',
  }
);

Generate Image.code:
// Generate an image from a text prompt.
// The base64-encoded image is written to state.
generateImage(
  `A flat-design illustration of: ${$.data.subject}`,
  {
    // Image-capable model — defaults to gemini-3-pro-image-preview.
    model: 'gemini-3-pro-image-preview',
    // Output size hint (e.g. '1K', '2K').
    imageSize: '1K',
    // Aspect ratio: '1:1', '16:9', '9:16', '4:3', '3:4'.
    aspectRatio: '16:9',
  }
);

Send Prompt.code:
// Send a prompt to Gemini.
// The text reply is written to state.data.response.
prompt(
  `Summarize this text: ${JSON.stringify($.data)}`,
  {
    // Gemini model id (see https://ai.google.dev/gemini-api/docs/models).
    model: 'gemini-2.5-flash',
    config: {
      temperature: 0.7,
    },
  }
);
